long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    long long total = 0;

    vector<pair<long long, long long>> intervals;

    for (int i = 0; i < n; ++i) {
        long long max_val = nums[i];
        long long min_val = nums[i];
        for (int j = i; j < n; ++j) {
            max_val = max(max_val, nums[j]);
            min_val = min(min_val, nums[j]);
            intervals.emplace_back(max_val - min_val, j - i + 1);
        }
    }

    sort(intervals.begin(), intervals.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
        return a.first > b.first;
    });

    for (int i = 0; i < k && i < intervals.size(); ++i) {
        total += intervals[i].first;
    }

    return total;
}
